public void insert()
{
    next insert();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        DimensionAttributeValue dimAttrValue = DimensionAttributeValue::find(this.DimensionAttributeValue);
        str descriptiveKeyCollection = strFmt("FinancialDimension='%1', DimensionValue='%2', LegalEntityId='%3'",
            DimensionAttribute::find(dimAttrValue.DimensionAttribute).Name,
            dimAttrValue.DisplayValue,
            Ledger::find(this.Ledger).Name);


        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("FinancialDimensionValueLegalEntityOverridesV2");
        contract.parmoperationType("Insert");

        ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);
        eventClass.send();
    }

}

